import os
import boto3

os.environ['AWS_BEARER_TOKEN_BEDROCK'] = 'bedrock-api-key-'

bedrock_client = boto3.client('bedrock-runtime', region_name='us-east-1')

def test_model(model_id):
    try:
        response = bedrock_client.converse(
            modelId=model_id,
            messages=[{'role': 'user', 'content': [{'text': 'Reply with a single word "Yes"'}]}]
        )
        print(f"Success for {model_id}:", response['output']['message']['content'][0]['text'])
    except Exception as e:
        print(f"Error for {model_id}: {e}")

test_model('meta.llama3-70b-instruct-v1:0')
test_model('mistral.mistral-large-2402-v1:0')
